const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'pe-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{ json: { valid: 0, error: 'pong' } }];
}

// __AUTH_PATCH_V1__
// === SSO Phase 3: token presence check ===
// Без токена → auth_required, фронт redirect на /login.html
const __token = String((body && body.token) || '').trim();
const __userName = String((body && body.user_name) || '').trim().slice(0, 80);
if (!__token || !/^[a-f0-9]{64}$/.test(__token)) {
  return [{json: {valid: 0, error: 'auth_required', auth_required: true}}];
}


if (!message || message.length < 2) {
  return [{ json: { valid: 0, error: 'Введите сообщение' } }];
}

if (message.length > 10000) {
  return [{ json: { valid: 0, error: 'Слишком длинный запрос (максимум 10000 символов)' } }];
}

// Защита от SQL-инъекций через session_id (дальше используется в WHERE session_id = $1)
if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{ json: { valid: 0, error: 'session_id содержит недопустимые символы' } }];
}

return [{ json: { valid: 1, message: message, session_id: session_id, token: __token, user_name: __userName } }];

const message = $('Агрегация').first().json.message;
const historyContext = $('Агрегация').first().json.historyContext || '';
const lower = message.toLowerCase();

const promptKeywords = [
  'промпт', 'prompt', 'системн', 'создай', 'напиши', 'сгенерируй',
  'адаптируй', 'адаптировать', 'переделай', 'переделать', 'перепиши под',
  'переписать под', 'измени под', 'изменить под', 'подстрой', 'подстроить',
  'улучши', 'улучшить', 'доработай', 'доработать', 'оптимизируй',
  'оптимизировать', 'исправь промпт', 'усиль', 'усилить', 'сделай лучше',
  'что не так с промптом', 'проанализируй промпт',
  'инструкци', 'для модели', 'для нейросет', 'для ии', 'для ai',
  'для gigachat', 'для гигачат', 'для бота', 'для чат-бота',
  'роль ассистент', 'ты —', 'you are'
];

const hasExistingPrompt = (
  (message.includes('```') || message.includes('Ты —') || message.includes('Ты -') || message.includes('You are')) &&
  message.length > 100
);

let isPromptTask = hasExistingPrompt;
if (!isPromptTask) {
  for (const kw of promptKeywords) {
    if (lower.includes(kw)) { isPromptTask = true; break; }
  }
}

if (!isPromptTask && message.length > 50) {
  const taskIndicators = ['нужен', 'нужно', 'хочу', 'сделай', 'помоги написать', 'составь', 'разработай'];
  for (const kw of taskIndicators) {
    if (lower.includes(kw)) { isPromptTask = true; break; }
  }
}

if (!isPromptTask) {
  return [{ json: { message, mode: 'general', modeLabel: 'Общение', historyContext } }];
}

const adaptKeywords = ['адаптируй', 'адаптировать', 'переделай', 'переделать', 'перепиши под', 'переписать под', 'измени под', 'изменить под', 'подстрой', 'подстроить'];
const improveKeywords = ['улучши', 'улучшить', 'доработай', 'доработать', 'оптимизируй', 'оптимизировать', 'исправь промпт', 'усиль', 'усилить', 'сделай лучше', 'что не так с промптом', 'проанализируй промпт'];

let mode = 'create';
let modeLabel = 'Создание нового промпта';

for (const kw of adaptKeywords) {
  if (lower.includes(kw)) { mode = 'adapt'; modeLabel = 'Адаптация промпта'; break; }
}

if (mode === 'create') {
  for (const kw of improveKeywords) {
    if (lower.includes(kw)) { mode = 'improve'; modeLabel = 'Улучшение промпта'; break; }
  }
}

if (mode === 'create' && hasExistingPrompt) {
  mode = 'improve';
  modeLabel = 'Улучшение промпта';
}

return [{ json: { message, mode, modeLabel, historyContext } }];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'GigaChat не отвечает. Проверьте подключение.', prompt: '' } }];
  }
  // Безопасный доступ — LLM при таймауте может вернуть пустой output
  const text = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!text) {
    return [{ json: { response: 'Пустой ответ от LLM. Попробуйте ещё раз.', prompt: '' } }];
  }
  return [{ json: { response: text.trim(), prompt: '' } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки.', prompt: '' } }];
}

try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{ json: { response: 'GigaChat не отвечает. Проверьте подключение.', prompt: '' } }];
  }

  // Безопасный доступ — LLM при таймауте может вернуть пустой output
  const generatedText = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!generatedText) {
    return [{ json: { response: 'Пустой ответ от LLM. Попробуйте ещё раз.', prompt: '' } }];
  }

  // Многоступенчатый парсинг — GigaChat часто пишет ``` нестандартно
  // (без переноса строки после открывающего, без указания языка,
  // случайно с одним backtick'ом и т.п.). Раньше падали в пустой
  // extras.prompt и кнопка «Копировать» вообще не появлялась.
  let extractedPrompt = '';
  let extractionNote = '';

  // Попытка 1: канонический формат ```lang\n...```
  let m = generatedText.match(/```\w*\s*\n([\s\S]*?)```/);
  if (m) {
    extractedPrompt = m[1].trim();
  } else {
    // Попытка 2: ``` без \n после открывающего
    m = generatedText.match(/```\w*\s*([\s\S]*?)```/);
    if (m) extractedPrompt = m[1].trim();
  }
  if (!extractedPrompt) {
    // Попытка 3: любые ``` ... ``` без языка
    m = generatedText.match(/```([\s\S]*?)```/);
    if (m) extractedPrompt = m[1].trim();
  }
  if (!extractedPrompt) {
    // Попытка 4: код-блок в одинарных backtick'ах в начале строки
    m = generatedText.match(/^`([^`\n][\s\S]*?)`/m);
    if (m) extractedPrompt = m[1].trim();
  }
  if (!extractedPrompt) {
    // Fallback: GigaChat не вернул блок в стандартном формате.
    // Берём ВЕСЬ ответ как промпт — лучше показать что-то с возможностью
    // копирования, чем пустой блок. Пользователь сам разберётся.
    extractedPrompt = generatedText.trim();
    extractionNote = '\n\n_GigaChat не вернул промпт в стандартном формате ```...``` — показан весь ответ как есть._';
  }

  return [{ json: { response: generatedText + extractionNote, prompt: extractedPrompt } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки ответа GigaChat: ' + e.message, prompt: '' } }];
}

const historyRows = $input.all().reverse();
let historyContext = '';
if (historyRows.length > 0) {
  const lines = historyRows.map(item => {
    const role = item.json.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (item.json.content || '');
  });
  historyContext = 'История диалога:\n' + lines.join('\n') + '\n\n';
}
const v = $('Валидация').first().json;
return [{json: {message: v.message, session_id: v.session_id, historyContext: historyContext, user_name: (v.user_name || '')}}];

