const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
// PostgreSQL сбой: data может быть null или содержать .error поле — НЕ
// помечаем как unauthorized, иначе юзер видит ложный auth_required редирект.
if (data && data.error) {
  return [{ json: { token_valid: false, response: 'error', error: 'database_unavailable' } }];
}
if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}
return [{ json: { ...src, token_valid: true, user_id: data.user_id } }];
